#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Collisions;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.masterSpark)]
    public class MasterSpark : EntityBehaviourDefinition
    {
        public MasterSpark(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new Vector3Modifier(EngineEntityProps.DISPLAY_SCALE, NumberOperator.Multiply, PROP_SIZE_MULTIPLIER));
            AddModifier(new Vector3Modifier(EngineEntityProps.SIZE, NumberOperator.Multiply, PROP_SIZE_MULTIPLIER));
            AddModifier(new Vector3Modifier(LogicEntityProps.HSV_OFFSET, NumberOperator.Add, PROP_HSV_OFFSET));
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.PlaySound(VanillaSoundID.touhouLaser);
            SetSizeMultiplier(entity, new Vector3(1, 0.01f, 0.01f));
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (!entity.Parent.ExistsAndAlive() || entity.Parent.IsAIFrozen())
            { 
                entity.Remove();
                return;
            }

            var hsv = GetHSVOffset(entity);
            hsv.x += HUE_SPEED;
            SetHSVOffset(entity, hsv);

            if (entity.GetEntityTime() < EXPAND_TIME)
            {
                SetSizeMultiplier(entity, new Vector3(1, 0.01f, 0.01f));
            }
            else if (IsShrinking(entity))
            {
                var multiplier = GetSizeMultiplier(entity);
                multiplier = Vector3.Lerp(multiplier, new Vector3(1, 0, 0), entity.Timeout / (float)SHRINK_TIME);
                SetSizeMultiplier(entity, multiplier);
            }
            else
            {
                if (!IsSoundPlayed(entity))
                {
                    SetSoundPlayed(entity, true);
                    entity.PlaySound(VanillaSoundID.masterSpark);
                }
                entity.Level.ShakeScreen(1, 0, 15);
                var multiplier = GetSizeMultiplier(entity);
                multiplier = Ticks.SmoothDamp(multiplier, Vector3.one, 0.75f);
                SetSizeMultiplier(entity, multiplier);

                detectBuffer.Clear();
                laserDetector.DetectMultiple(entity, detectBuffer);
                var damageEffects = entity.GetDamageEffects();
                var damage = entity.GetDamage();
                var effects = damageEffects == null ? new DamageEffectList() : new DamageEffectList(damageEffects);
                foreach (var target in detectBuffer)
                {
                    target.TakeDamage(damage, effects, entity);
                }
            }
        }
        public static bool IsShrinking(Entity entity)
        {
            return entity.Timeout < SHRINK_TIME;
        }
        public static bool IsSoundPlayed(Entity entity) => entity.GetBehaviourField<bool>(PROP_SOUND_PLAYED);
        public static void SetSoundPlayed(Entity entity, bool value) => entity.SetBehaviourField(PROP_SOUND_PLAYED, value);
        public static Vector3 GetSizeMultiplier(Entity entity) => entity.GetBehaviourField<Vector3>(PROP_SIZE_MULTIPLIER);
        public static void SetSizeMultiplier(Entity entity, Vector3 value) => entity.SetBehaviourField(PROP_SIZE_MULTIPLIER, value);
        public static Vector3 GetHSVOffset(Entity entity) => entity.GetBehaviourField<Vector3>(PROP_HSV_OFFSET);
        public static void SetHSVOffset(Entity entity, Vector3 value) => entity.SetBehaviourField(PROP_HSV_OFFSET, value);

        public static readonly VanillaEntityPropertyMeta<bool> PROP_SOUND_PLAYED = new VanillaEntityPropertyMeta<bool>("sound_played");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_SIZE_MULTIPLIER = new VanillaEntityPropertyMeta<Vector3>("size_multiplier");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_HSV_OFFSET = new VanillaEntityPropertyMeta<Vector3>("hsv_offset");
        public const int EXPAND_TIME = 30;
        public const int SHRINK_TIME = 15;
        public const float HUE_SPEED = 10;
        public static Detector laserDetector = new CollisionDetector(true);
        public HashSet<IEntityCollider> detectBuffer = new HashSet<IEntityCollider>();
    }
}
